```class Solution {
    public int clumsy(int n) {
        int res = n;
        int op = 1;
        for (int i = n - 1; i > 1; i--) {
            if (op == 1) {
                res *= i;
            } else if (op == 2) {
                res /= i;
            } else if (op == 3) {
                res += i;
            } else {
                res -= i;
            }
            op = (op + 1) % 4;
        }
        return res;
    }
}```
